SELECT baseline."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption__baseline", sum(upgrade."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(baseline."out.electricity.total.energy_consumption", 0) - coalesce(upgrade."out.electricity.total.energy_consumption", 0)) * baseline.weight) AS "electricity.total.energy_consumption__savings", approx_percentile(baseline."out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__baseline__quartiles", approx_percentile(baseline."out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE baseline."out.electricity.total.energy_consumption" != 0) AS "electricity.total.energy_consumption__baseline__nonzero_quartiles", approx_percentile(upgrade."out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__upgrade__quartiles", approx_percentile(upgrade."out.electricity.total.energy_consumption", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE upgrade."out.electricity.total.energy_consumption" != 0) AS "electricity.total.energy_consumption__upgrade__nonzero_quartiles", approx_percentile(coalesce(baseline."out.electricity.total.energy_consumption", 0) - coalesce(upgrade."out.electricity.total.energy_consumption", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption__savings__quartiles", approx_percentile(coalesce(baseline."out.electricity.total.energy_consumption", 0) - coalesce(upgrade."out.electricity.total.energy_consumption", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE coalesce(baseline."out.electricity.total.energy_consumption", 0) - coalesce(upgrade."out.electricity.total.energy_consumption", 0) != 0) AS "electricity.total.energy_consumption__savings__nonzero_quartiles" FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND upgrade.upgrade = 1 AND upgrade.applicability = true WHERE baseline.applicability = true AND baseline."in.state" = 'CO' GROUP BY 1 ORDER BY 1